#include<bits/stdc++.h>
using namespace std;
int n,m;
int a[101],flag[101],dp[10001];
map<int,bool> mp;
int ans=0;
void dfs(int x,int cnt)
{
    if(cnt>m)
    {
        return;
    }
    if(cnt+n+1-x<m)
    {
        return;
    }
    if(x==n+1)
    {
        memset(dp,0,sizeof(dp));
        dp[0]=1;
        for(int i=1;i<=n;i++)
        {
            if(!flag[i])
            {
                for(int j=2000;j>=a[i];j--)
                {
                    dp[j]|=dp[j-a[i]];
                }
            }
        }
        int cnt=0;
        for(int i=1;i<=2000;i++)
        {
            cnt+=dp[i];
        }
        ans=max(ans,cnt);
        return;
    }
    flag[x]=0;
    dfs(x+1,cnt);
    flag[x]=1;
    dfs(x+1,cnt+1);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    dfs(1,0);
    printf("%d",ans);
    return 0;
}
